queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?research_papers a :Research_Papers .
    ?research_papers p:title ?title .
    ?research_papers p:citation_style ?citation_style_f .
    FILTER(STR(?citation_style_f) = "APA")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?review_articles a :Review_Articles .
    ?review_articles p:title ?title .
    ?review_articles p:citation_style ?citation_style_f .
    FILTER(STR(?citation_style_f) = "APA")
    BIND(?title AS ?o0)
  }
}

